import 'dart:convert';

import '../lib/websocket_decoder.dart';
import '../lib/websocket_frame.dart';
import '../lib/websocket_messages.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final decoder = WebSocketDecoder();
  check(decoder.add(<int>[0x81]).isEmpty, 'waits for a partial frame header');
  final completed = decoder.add(<int>[0x05, ...utf8.encode('hello')]);
  check(
    completed.length == 1 && utf8.decode(completed.single.payload) == 'hello',
    'retains transport bytes until the frame is complete',
  );

  final assembler = WebSocketMessageAssembler();
  assembler.add(
    WebSocketFrame(
      finalFragment: false,
      opcode: 0x01,
      payload: utf8.encode('hel'),
    ),
  );
  assembler.add(
    WebSocketFrame(finalFragment: true, opcode: 0x09, payload: const <int>[]),
  );
  final messages = assembler.add(
    WebSocketFrame(
      finalFragment: true,
      opcode: 0x00,
      payload: utf8.encode('lo'),
    ),
  );
  check(
    messages.length == 1 && messages.single == 'hello',
    'control traffic does not discard an active fragmented message',
  );

  print('feedback tests passed');
}
